const formatStatus = global.get('utils.formatStatus', 'initializers') || (t => t);
const {
    dateLabel, timeLabel, appointments, reminders,
    trashToday, trashTomorrow, today, tomorrow,
    todayForecast, activeAlerts, batteriesNeedingAttention, connections
} = msg.digestData;

// ─────────────────────────────────────────────
// Utility functions
// ─────────────────────────────────────────────

function esc(str) {
    return String(str || '')
        .replace(/&/g, '&amp;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;')
        .replace(/"/g, '&quot;');
}

function formatTimeRange(start, end) {
    const fmt = iso => {
        const d = new Date(iso);
        const h = d.getHours() % 12 || 12;
        const m = d.getMinutes();
        const ap = d.getHours() >= 12 ? 'PM' : 'AM';
        return m === 0 ? `${h} ${ap}` : `${h}:${m.toString().padStart(2,'0')} ${ap}`;
    };
    return `${fmt(start)} \u2013 ${fmt(end)}`;
}

function formatHour(iso) {
    return String(new Date(iso).getHours() % 12 || 12);
}

function formatAmPm(iso) {
    return new Date(iso).getHours() >= 12 ? 'PM' : 'AM';
}

function formatDateFull(dateStr) {
    return new Date(dateStr + 'T12:00:00').toLocaleDateString('en-US', {
        weekday: 'long', month: 'long', day: 'numeric'
    });
}

// ─────────────────────────────────────────────
// Meteocons icon mapping
// NWS condition code → Meteocons filename (without .png)
// ─────────────────────────────────────────────

function getMeteoconName(code, isDaytime) {
    const day = isDaytime;
    switch (code) {
        // Clear
        case 'skc':
        case 'few':
            return day ? 'clear-day' : 'clear-night';
        // Partly cloudy
        case 'sct':
            return day ? 'partly-cloudy-day' : 'partly-cloudy-night';
        // Mostly cloudy
        case 'bkn':
            return day ? 'overcast-day' : 'overcast-night';
        // Overcast
        case 'ovc':
            return 'overcast';
        // Windy variants
        case 'wind_skc':
        case 'wind_few':
            return day ? 'clear-day' : 'clear-night';
        case 'wind_sct':
        case 'wind_bkn':
        case 'wind_ovc':
            return 'wind';
        // Rain
        case 'rain':
        case 'rain_showers':
        case 'rain_showers_hi':
            return 'rain';
        // Freezing rain / mixed
        case 'fzra':
        case 'rain_fzra':
        case 'snow_fzra':
            return day ? 'overcast-day-sleet' : 'overcast-night-sleet';
        // Rain/snow mix
        case 'rain_snow':
            return day ? 'partly-cloudy-day-sleet' : 'partly-cloudy-night-sleet';
        // Sleet
        case 'sleet':
        case 'rain_sleet':
        case 'snow_sleet':
            return 'sleet';
        // Snow
        case 'snow':
            return 'snow';
        // Blizzard
        case 'blizzard':
            return 'extreme-snow';
        // Thunderstorms
        case 'tsra':
        case 'tsra_sct':
        case 'tsra_hi':
            return day ? 'thunderstorms-day' : 'thunderstorms-night';
        // Severe
        case 'tornado':
            return 'tornado';
        case 'hurricane':
        case 'tropical_storm':
            return 'hurricane';
        // Obscured
        case 'fog':
            return day ? 'fog-day' : 'fog-night';
        case 'smoke':
            return 'smoke';
        case 'haze':
            return day ? 'haze-day' : 'haze-night';
        case 'dust':
            return day ? 'dust-day' : 'dust-night';
        // Temperature extremes
        case 'hot':
            return 'thermometer-sun';
        case 'cold':
            return 'thermometer-snow';
        // Default
        default:
            return day ? 'clear-day' : 'clear-night';
    }
}

// Track which icons are used so Build SMTP Message knows what to attach
const usedIcons = new Set();

function weatherImg(code, isDaytime, width, height, extraStyle) {
    const name = getMeteoconName(code, isDaytime);
    usedIcons.add(name);
    const style = extraStyle || 'display:block;';
    return `<img src="cid:${name}.png" width="${width}" height="${height}" alt="" style="${style}" />`;
}

function getWeatherIconLarge(code, isDaytime) {
    return weatherImg(code, isDaytime, 64, 64, 'display:block;margin:0 auto;');
}

function getWeatherIconSmall(code, isDaytime) {
    return weatherImg(code, isDaytime, 48, 48, 'display:inline-block;');
}

function severityColor(s) {
    return { Extreme: '#dc2626', Severe: '#ea580c', Moderate: '#d97706', Minor: '#ca8a04' }[s] || '#d97706';
}
function severityBg(s) {
    return { Extreme: '#fef2f2', Severe: '#fff7ed', Moderate: '#fef3c7', Minor: '#fefce8' }[s] || '#fef3c7';
}

// ─────────────────────────────────────────────
// Layout primitives
// ─────────────────────────────────────────────

function divider() {
    return `<tr><td style="padding:28px 40px 0;">
        <table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0">
          <tr><td style="height:1px;background-color:#ebebeb;"></td></tr>
        </table>
      </td></tr>`;
}

function sectionHeader(label, title, accentColor) {
    return `<tr><td style="padding:28px 40px 0;">
        <table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0">
          <tr><td style="border-left:3px solid ${accentColor};padding-left:12px;">
            <p style="margin:0;font-family:'Courier New',Courier,monospace;font-size:9px;letter-spacing:3px;text-transform:uppercase;color:${accentColor};">${label}</p>
            <h2 style="margin:3px 0 0;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Helvetica,Arial,sans-serif;font-size:18px;font-weight:600;color:#1a1f2e;">${title}</h2>
          </td></tr>
        </table>
      </td></tr>`;
}

// ─────────────────────────────────────────────
// Section builders
// ─────────────────────────────────────────────

function buildAppointments() {
    if (!appointments || !appointments.length) return '';
    const items = appointments.map(e => `
        <tr><td style="padding:0 0 8px 0;">
          <table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" style="background-color:#f8f8f6;border-radius:8px;">
            <tr><td style="padding:16px 20px;">
              <table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0">
                <tr>
                  <td valign="top" width="56">
                    <div style="background-color:#e8f0fe;border-radius:6px;padding:7px 0;text-align:center;width:44px;">
                      <p style="margin:0;font-family:'Courier New',Courier,monospace;font-size:16px;font-weight:bold;color:#4f7df0;line-height:1;">${formatHour(e.start)}</p>
                      <p style="margin:1px 0 0;font-family:'Courier New',Courier,monospace;font-size:8px;letter-spacing:1px;color:#7a9bd4;text-transform:uppercase;">${formatAmPm(e.start)}</p>
                    </div>
                  </td>
                  <td style="padding-left:14px;" valign="top">
                    <p style="margin:0 0 3px 0;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Helvetica,Arial,sans-serif;font-size:15px;font-weight:600;color:#1a1f2e;">${esc(e.title)}</p>
                    <p style="margin:0;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Helvetica,Arial,sans-serif;font-size:13px;color:#6b7280;">${e.end ? formatTimeRange(e.start, e.end) : formatHour(e.start) + ' ' + formatAmPm(e.start)}</p>
                  </td>
                </tr>
              </table>
            </td></tr>
          </table>
        </td></tr>`).join('');

    return sectionHeader('Today', 'Appointments', '#4f7df0') +
        `<tr><td style="padding:16px 40px 0;"><table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0">${items}</table></td></tr>` +
        divider();
}

function buildReminders() {
    if (!reminders || !reminders.length) return '';
    const items = reminders.map(e => `
        <tr><td style="padding-bottom:8px;">
          <table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" style="background-color:#f8f4ff;border-radius:8px;">
            <tr><td style="padding:13px 18px;">
              <table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0">
                <tr>
                  <td width="24" valign="middle"><div style="width:7px;height:7px;background-color:#7b5ea7;border-radius:50%;"></div></td>
                  <td valign="middle"><p style="margin:0;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Helvetica,Arial,sans-serif;font-size:14px;color:#1a1f2e;">${esc(e.title)}</p></td>
                </tr>
              </table>
            </td></tr>
          </table>
        </td></tr>`).join('');

    return sectionHeader('Today', 'Reminders', '#7b5ea7') +
        `<tr><td style="padding:16px 40px 0;"><table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0">${items}</table></td></tr>` +
        divider();
}

function buildTrash() {
    const hasToday = trashToday && trashToday.length > 0;
    const hasTomorrow = trashTomorrow && trashTomorrow.length > 0;
    if (!hasToday && !hasTomorrow) return '';

    const label = hasToday ? 'Today' : 'Tomorrow';
    const date = hasToday ? today : tomorrow;

    return sectionHeader('Pickup Schedule', 'Trash &amp; Recycling', '#e8734a') +
        `<tr><td style="padding:16px 40px 0;">
          <table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" style="background-color:#fff8f5;border-radius:8px;border:1px solid #fdddd0;">
            <tr><td style="padding:20px 24px;">
              <table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0">
                <tr>
                  <td width="50%" valign="top" style="padding-right:16px;">
                    <p style="margin:0 0 3px 0;font-family:'Courier New',Courier,monospace;font-size:9px;letter-spacing:2px;text-transform:uppercase;color:#e8734a;">Trash</p>
                    <p style="margin:0 0 2px 0;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Helvetica,Arial,sans-serif;font-size:20px;font-weight:700;color:#1a1f2e;">${label}</p>
                    <p style="margin:0;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Helvetica,Arial,sans-serif;font-size:12px;color:#9ca3af;">${formatDateFull(date)}</p>
                  </td>
                  <td width="1" style="background-color:#fdddd0;"></td>
                  <td width="50%" valign="top" style="padding-left:24px;">
                    <p style="margin:0 0 3px 0;font-family:'Courier New',Courier,monospace;font-size:9px;letter-spacing:2px;text-transform:uppercase;color:#e8734a;">Recycling</p>
                    <p style="margin:0 0 2px 0;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Helvetica,Arial,sans-serif;font-size:20px;font-weight:700;color:#1a1f2e;">${label}</p>
                    <p style="margin:0;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Helvetica,Arial,sans-serif;font-size:12px;color:#9ca3af;">${formatDateFull(date)}</p>
                  </td>
                </tr>
              </table>
            </td></tr>
          </table>
        </td></tr>` +
        divider();
}

function buildWeather() {
    if (!todayForecast) return '';

    const day = todayForecast.daytime;
    const night = todayForecast.overnight;

    const alertBanners = (activeAlerts || []).map(a => `
        <tr><td style="padding:0 0 10px 0;">
          <table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" style="background-color:${severityBg(a.severity)};border-radius:8px;border-left:4px solid ${severityColor(a.severity)};">
            <tr><td style="padding:14px 18px;">
              <table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0">
                <tr>
                  <td valign="top" width="28"><p style="margin:0;font-size:15px;line-height:1.3;">&#9888;&#65039;</p></td>
                  <td valign="top" style="padding-left:8px;">
                    <p style="margin:0 0 2px 0;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Helvetica,Arial,sans-serif;font-size:13px;font-weight:700;color:${severityColor(a.severity)};">${esc(a.event)}</p>
                    <p style="margin:0;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Helvetica,Arial,sans-serif;font-size:13px;color:#374151;">${esc(a.headline)}</p>
                  </td>
                </tr>
              </table>
            </td></tr>
          </table>
        </td></tr>`).join('');

    const dayPanel = day ? `
        <td width="50%" valign="top" align="center" style="padding-right:20px;">
          <p style="margin:0 0 10px 0;font-family:'Courier New',Courier,monospace;font-size:9px;letter-spacing:2px;text-transform:uppercase;color:#0ea5e9;">Today</p>
          <table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" style="margin-bottom:12px;">
            <tr><td align="center" style="padding-bottom:8px;">${getWeatherIconLarge(day.icon, true)}</td></tr>
            <tr><td align="center">
              <p style="margin:0;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Helvetica,Arial,sans-serif;font-size:36px;font-weight:700;color:#1a1f2e;line-height:1;">${day.temperature}&deg;</p>
              <p style="margin:3px 0 0;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Helvetica,Arial,sans-serif;font-size:12px;color:#64748b;">${esc(day.shortForecast)}</p>
            </td></tr>
          </table>
          <table role="presentation" cellpadding="0" cellspacing="0" border="0" style="margin:0 auto;">
            <tr>
              <td style="width:50%;text-align:center;">
                <p style="margin:0;font-family:'Courier New',Courier,monospace;font-size:9px;color:#94a3b8;text-transform:uppercase;letter-spacing:1px;">Precip</p>
                <p style="margin:2px 0 0;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Helvetica,Arial,sans-serif;font-size:12px;color:#334155;font-weight:600;">${day.precipChance}%</p>
              </td>
              <td style="width:50%;text-align:center;">
                <p style="margin:0;font-family:'Courier New',Courier,monospace;font-size:9px;color:#94a3b8;text-transform:uppercase;letter-spacing:1px;">Wind</p>
                <p style="margin:2px 0 0;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Helvetica,Arial,sans-serif;font-size:12px;color:#334155;font-weight:600;">${esc(day.windDirection)} ${esc(day.windSpeed)}</p>
              </td>
            </tr>
          </table>
        </td>` : `<td width="50%"></td>`;

    const nightPanel = night ? `
        <td width="50%" valign="top" align="center" style="padding-left:24px;">
          <p style="margin:0 0 10px 0;font-family:'Courier New',Courier,monospace;font-size:9px;letter-spacing:2px;text-transform:uppercase;color:#0ea5e9;">Tonight</p>
          <table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" style="margin-bottom:12px;">
            <tr><td align="center" style="padding-bottom:8px;">${getWeatherIconLarge(night.icon, false)}</td></tr>
            <tr><td align="center">
              <p style="margin:0;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Helvetica,Arial,sans-serif;font-size:36px;font-weight:700;color:#1a1f2e;line-height:1;">${night.temperature}&deg;</p>
              <p style="margin:3px 0 0;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Helvetica,Arial,sans-serif;font-size:12px;color:#64748b;">${esc(night.shortForecast)}</p>
            </td></tr>
          </table>
          <table role="presentation" cellpadding="0" cellspacing="0" border="0" style="margin:0 auto;">
            <tr>
              <td style="width:50%;text-align:center;">
                <p style="margin:0;font-family:'Courier New',Courier,monospace;font-size:9px;color:#94a3b8;text-transform:uppercase;letter-spacing:1px;">Precip</p>
                <p style="margin:2px 0 0;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Helvetica,Arial,sans-serif;font-size:12px;color:#334155;font-weight:600;">${night.precipChance}%</p>
              </td>
              <td style="width:50%;text-align:center;">
                <p style="margin:0;font-family:'Courier New',Courier,monospace;font-size:9px;color:#94a3b8;text-transform:uppercase;letter-spacing:1px;">Wind</p>
                <p style="margin:2px 0 0;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Helvetica,Arial,sans-serif;font-size:12px;color:#334155;font-weight:600;">${esc(night.windDirection)} ${esc(night.windSpeed)}</p>
              </td>
            </tr>
          </table>
        </td>` : `<td width="50%"></td>`;

    // 5-day forecast
    const forecastData = flow.get('weather_forecast');
    const timezone = global.get('config')?.location?.timezone || 'America/New_York';
    const now = new Date();
    const fiveDayDates = [];
    for (let i = 1; i <= 5; i++) {
        const d = new Date(now);
        d.setDate(d.getDate() + i);
        fiveDayDates.push(d.toLocaleDateString('en-CA', { timeZone: timezone }));
    }

    const fiveDayCols = fiveDayDates.map(date => {
        const p = forecastData?.periods?.[date];
        if (!p) return `<td width="20%" align="center" style="padding:0 4px;"></td>`;
        const dayData = p.daytime || p.overnight;
        if (!dayData) return `<td width="20%" align="center" style="padding:0 4px;"></td>`;
        const dayName = new Date(date + 'T12:00:00').toLocaleDateString('en-US', { weekday: 'short' });
        const high = p.daytime?.temperature ?? '\u2013';
        const low = p.overnight?.temperature ?? '\u2013';
        const icon = getWeatherIconSmall(dayData.icon, !!p.daytime);
        const label = esc(dayData.shortForecast.length > 18 ? dayData.shortForecast.slice(0, 17) + '\u2026' : dayData.shortForecast);
        return `<td width="20%" valign="top" align="center" style="padding:0 4px;">
          <p style="margin:0 0 6px 0;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Helvetica,Arial,sans-serif;font-size:11px;font-weight:600;color:#64748b;">${dayName}</p>
          <div style="text-align:center;margin:0 auto 6px;">${icon}</div>
          <p style="margin:0;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Helvetica,Arial,sans-serif;font-size:13px;font-weight:700;color:#1a1f2e;">${high}&deg;</p>
          <p style="margin:1px 0 5px;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Helvetica,Arial,sans-serif;font-size:11px;color:#94a3b8;">${low}&deg;</p>
          <p style="margin:0;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Helvetica,Arial,sans-serif;font-size:11px;color:#475569;line-height:1.3;">${label}</p>
        </td>`;
    }).join('');

    const alertTopPadding = (activeAlerts && activeAlerts.length) ? 'padding:12px 40px 0;' : 'padding:16px 40px 0;';

    return sectionHeader('Forecast', 'Weather', '#0ea5e9') +
        ((activeAlerts && activeAlerts.length) ? `<tr><td style="padding:16px 40px 0;"><table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0">${alertBanners}</table></td></tr>` : '') +
        `<tr><td style="${alertTopPadding}">
          <table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" style="background-color:#f0f9ff;border-radius:8px;border:1px solid #bae6fd;">
            <tr><td style="padding:22px 24px 20px;">
              <table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0">
                <tr>${dayPanel}<td width="1" style="background-color:#bae6fd;width:1px;"></td>${nightPanel}</tr>
              </table>
            </td></tr>
            <tr><td style="padding:0 24px;"><table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0"><tr><td style="height:1px;background-color:#bae6fd;"></td></tr></table></td></tr>
            <tr><td style="padding:18px 24px 20px;">
              <p style="margin:0 0 14px 0;font-family:'Courier New',Courier,monospace;font-size:9px;letter-spacing:2px;text-transform:uppercase;color:#0ea5e9;">5-Day Forecast</p>
              <table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0"><tr>${fiveDayCols}</tr></table>
            </td></tr>
          </table>
        </td></tr>` +
        divider();
}

function buildBattery() {
    if (!batteriesNeedingAttention || !batteriesNeedingAttention.length) return '';
    const items = batteriesNeedingAttention.map(b => {
        const isCritical = b.state === 'critical';
        const bg = isCritical ? '#fff5f5' : '#fffbeb';
        const border = isCritical ? '#ef4444' : '#f59e0b';
        const color = isCritical ? '#ef4444' : '#f59e0b';
        const friendlyName = esc(b.key.replace(/_/g, ' ').replace(/\b\w/g, c => c.toUpperCase()));
        const batterySpec = b.battery ? `Replace ${b.battery.quantity}\u00d7 ${b.battery.type}` : 'Replace battery';
        return `<tr><td style="padding-bottom:8px;">
          <table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" style="background-color:${bg};border-radius:8px;border-left:4px solid ${border};">
            <tr><td style="padding:13px 18px;">
              <table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0">
                <tr>
                  <td valign="middle">
                    <p style="margin:0 0 2px 0;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Helvetica,Arial,sans-serif;font-size:14px;font-weight:600;color:#1a1f2e;">${friendlyName}</p>
                    <p style="margin:0;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Helvetica,Arial,sans-serif;font-size:12px;color:#9ca3af;">${batterySpec}</p>
                  </td>
                  <td align="right" valign="middle" width="52">
                    <p style="margin:0;font-family:'Courier New',Courier,monospace;font-size:20px;font-weight:bold;color:${color};">${b.level}%</p>
                  </td>
                </tr>
              </table>
            </td></tr>
          </table>
        </td></tr>`;
    }).join('');

    return sectionHeader('Needs Attention', 'Battery Status', '#f59e0b') +
        `<tr><td style="padding:16px 40px 0;"><table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0">${items}</table></td></tr>` +
        divider();
}

function buildHealth() {
    const services = [
        { label: 'MQTT Broker', key: 'mqtt' },
        { label: 'Home Assistant', key: 'home_assistant' }
    ];
    const allHealthy = services.every(s => connections[s.key] !== 'down');
    const bg = allHealthy ? '#f0fdf4' : '#fff5f5';
    const border = allHealthy ? '#bbf7d0' : '#fecaca';
    const label = allHealthy ? 'All Systems' : 'Issues Detected';

    const dots = services.map(s => {
        const isUp = connections[s.key] !== 'down';
        const dotColor = isUp ? '#10b981' : '#ef4444';
        return `<table role="presentation" cellpadding="0" cellspacing="0" border="0">
          <tr>
            <td width="10" valign="middle"><div style="width:7px;height:7px;background-color:${dotColor};border-radius:50%;"></div></td>
            <td style="padding-left:8px;" valign="middle"><p style="margin:0;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Helvetica,Arial,sans-serif;font-size:13px;color:#374151;">${s.label}</p></td>
          </tr>
        </table>`;
    });

    const rows = [];
    for (let i = 0; i < dots.length; i += 2) {
        rows.push(`<tr>
          <td width="50%" style="padding-right:8px;${i > 0 ? 'padding-top:10px;' : ''}">${dots[i] || ''}</td>
          <td width="50%" style="padding-left:8px;${i > 0 ? 'padding-top:10px;' : ''}">${dots[i+1] || ''}</td>
        </tr>`);
    }

    return sectionHeader(label, 'System Health', '#10b981') +
        `<tr><td style="padding:16px 40px 32px;">
          <table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" style="background-color:${bg};border-radius:8px;border:1px solid ${border};">
            <tr><td style="padding:16px 20px;">
              <table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0">${rows.join('')}</table>
            </td></tr>
          </table>
        </td></tr>`;
}

