msg.emailHtml = html;
msg.emailSubject = `Highland Smart Home Daily Digest \u2014 ${dateLabel}`;
msg.usedIcons = Array.from(usedIcons);
node.status({ fill: 'green', shape: 'dot', text: formatStatus(`Email built — ${usedIcons.size} icons`) });
return msg;

const secrets = global.get('config')?.secrets;
const notifications = global.get('config')?.notifications;
const emailAddresses = secrets?.email_addresses || {};
const recipients = notifications?.daily_digest?.recipients || [];
const iconBasePath = '/assets/weather-icons/64/';

const to = recipients
    .map(r => emailAddresses[r])
    .filter(Boolean)
    .join(',');

// Build CID attachments for every icon referenced in the email.
// msg.usedIcons is a de-duplicated array of Meteocon names (without .png)
// set by Build Email — e.g. ['clear-day', 'overcast-night', 'rain']
const attachments = (msg.usedIcons || []).map(name => ({
    filename: `${name}.png`,
    path: `${iconBasePath}${name}.png`,
    cid: `${name}.png`,
    contentType: 'image/png'
}));

msg.to = to;
msg.from = emailAddresses['home'];
msg.topic = msg.emailSubject;
msg.payload = msg.emailHtml;
msg.attachments = attachments;

node.status({
    fill: 'blue',
    shape: 'dot',
    text: `Sending to ${to} — ${attachments.length} attachments`
});

return msg;
